+fn render_create_form_label(
+    frame: &mut Frame<'_>,
+    inner: Rect,
+    cursor_y: &mut u16,
+    bottom: u16,
+    label: &str,
+    focused: bool,
+    tp: &crate::tui_theme::TuiThemePalette,
+) {
+    if *cursor_y >= bottom {
+        return;
+    }
+    let style = if focused {
+        Style::default().fg(tp.selection_indicator).bold()
+    } else {
+        crate::tui_theme::text_meta(tp)
+    };
+    Paragraph::new(label)
+        .style(style)
+        .render(Rect::new(inner.x, *cursor_y, inner.width, 1), frame);
+    *cursor_y = (*cursor_y).saturating_add(1);
+}
+
+fn render_create_form_error(
+    frame: &mut Frame<'_>,
+    inner: Rect,
+    cursor_y: &mut u16,
+    bottom: u16,
+    error: Option<&str>,
+    tp: &crate::tui_theme::TuiThemePalette,
+) {
+    if let Some(error) = error
+        && *cursor_y < bottom
+    {
+        Paragraph::new(error)
+            .style(crate::tui_theme::text_warning(tp))
+            .render(Rect::new(inner.x, *cursor_y, inner.width, 1), frame);
+        *cursor_y = (*cursor_y).saturating_add(1);
+    }
+}
