+    block.render(modal, frame);
+    if inner.height < 10 || inner.width < 18 {
+        return;
+    }
+
+    let mut cursor_y = inner.y;
+    let bottom = inner.y + inner.height;
+
+    let project_label = if form.project_slug.is_empty() {
+        "(unknown)"
