+    cursor_y = cursor_y.saturating_add(1);
+    Paragraph::new(format!("Agent:   {agent_label}"))
+        .style(crate::tui_theme::text_hint(&tp))
+        .render(Rect::new(inner.x, cursor_y, inner.width, 1), frame);
+    cursor_y = cursor_y.saturating_add(1);
+
+    render_create_form_label(
